SELECT COUNT(*) AS QTD FROM LATTES_P_EVENTO LPE JOIN LATTES_EVENTO LE ON LE.PK = LPE.FK_EVENTO JOIN SERVIDOR S ON S.PK_SIAPE = LPE.FK_SIAPE WHERE LOWER(LPE.TIPO) = LOWER('apresentacao oral') AND LE.ANO = 2022 AND S.SIGLA_CAMPUS = 'ITU' AND S.GENERO = 'FEMININO' AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%letras%'